using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool, Description("Get the weather forecast for a US location by latitude and longitude.")]
    public static async Task<string> GetForecast(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var client = httpClientFactory.CreateClient("weather");

        // NWS API requires a point lookup first, then a forecast request.
        var pointUrl = $"/points/{latitude:F4},{longitude:F4}";
        using var pointDoc = await client.GetFromJsonAsync<JsonDocument>(pointUrl);
        var forecastUrl = pointDoc!.RootElement
            .GetProperty("properties")
            .GetProperty("forecast")
            .GetString()!;

        using var forecastDoc = await client.GetFromJsonAsync<JsonDocument>(forecastUrl);
        var periods = forecastDoc!.RootElement
            .GetProperty("properties")
            .GetProperty("periods")
            .EnumerateArray()
            .Take(3);

        return string.Join("\n---\n", periods.Select(p =>
            $"""
            {p.GetProperty("name").GetString()}
            Temperature: {p.GetProperty("temperature").GetInt32()}°{p.GetProperty("temperatureUnit").GetString()}
            Wind: {p.GetProperty("windSpeed").GetString()} {p.GetProperty("windDirection").GetString()}
            {p.GetProperty("detailedForecast").GetString()}
            """));
    }

    [McpServerTool, Description("Get active weather alerts for a US state (two-letter code, e.g. CA).")]
    public static async Task<string> GetAlerts(
        IHttpClientFactory httpClientFactory,
        [Description("Two-letter US state code")] string state)
    {
        var client = httpClientFactory.CreateClient("weather");
        using var doc = await client.GetFromJsonAsync<JsonDocument>(
            $"/alerts/active/area/{state}");

        var alerts = doc!.RootElement
            .GetProperty("features")
            .EnumerateArray()
            .Take(5)
            .Select(a =>
            {
                var props = a.GetProperty("properties");
                return $"""
                    {props.GetProperty("headline").GetString()}
                    Severity: {props.GetProperty("severity").GetString()}
                    {props.GetProperty("description").GetString()}
                    """;
            });

        return alerts.Any() ? string.Join("\n---\n", alerts) : "No active alerts.";
    }
}

